101→function AppInner() {
102→  const { project, isDirty, dispatch } = useProject();
103→  const [showLoadModal, setShowLoadModal] = useState(false);
104→  const [savedProjects, setSavedProjects] = useState([]);
105→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
106→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
107→
108→  useAutosave(project, isDirty, dispatch);
109→
110→  // beforeunload warning
111→  useEffect(() => {
112→    const handler = (e) => {
113→      if (isDirty) {
114→        e.preventDefault();
115→        e.returnValue = '';
116→      }
117→    };
118→    window.addEventListener('beforeunload', handler);
119→    return () => window.removeEventListener('beforeunload', handler);
120→  }, [isDirty]);
121→
122→  const handleNew = useCallback(() => {
123→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
124→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
125→  }, [isDirty, dispatch]);
126→
127→  const handleSave = useCallback(async () => {
128→    await saveProject(project);
129→    dispatch({ type: 'MARK_SAVED' });
130→  }, [project, dispatch]);
131→
132→  // Ctrl+S save
133→  useEffect(() => {
134→    const handler = (e) => {
135→      if (isTypingTarget(e.target)) return;
136→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
137→        e.preventDefault();
138→        handleSave();
139→      }
140→    };
141→    window.addEventListener('keydown', handler);
142→    return () => window.removeEventListener('keydown', handler);
143→  }, [handleSave]);
144→
145→  const handleLoadClick = useCallback(async () => {
146→    setSavedProjects(await listProjects());
147→    setShowLoadModal(true);
148→  }, []);
149→
150→  const handleLoad = useCallback(async (id) => {
151→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
152→    try {
153→      const { project: loaded, savedAt } = await loadProject(id);
154→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
155→      setShowLoadModal(false);
156→    } catch (err) {
157→      alert('Failed to load project: ' + err.message);
158→    }
159→  }, [isDirty, dispatch]);
160→
161→  const handleDelete = useCallback(async (id, name) => {
162→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
163→    if (!confirmed) return;
164→
165→    try {
166→      await deleteProject(id);
167→      setSavedProjects(projects => projects.filter(project => project.id !== id));
168→    } catch (err) {
169→      alert('Failed to delete project: ' + err.message);
170→    }
171→  }, []);
172→
173→  const activeFloorId = project.floors[0]?.id;
174→
175→  return (
176→    <EditorProvider activeFloorId={activeFloorId}>
177→      <EditorShell
178→        project={project}
179→        handleNew={handleNew}
180→        handleSave={handleSave}
181→        handleLoadClick={handleLoadClick}
182→        isSidebarCollapsed={isSidebarCollapsed}
183→        isPropertiesCollapsed={isPropertiesCollapsed}
184→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
185→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
186→      />
187→
188→      {showLoadModal && (
189→        <Modal title="Load Project" onClose={() => setShowLoadModal(false)}>
190→          {savedProjects.length === 0 ? (
191→            <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px' }}>
192→              No saved projects found.
193→            </p>
194→          ) : (
195→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
196→              {savedProjects.map(p => (
197→                <div
198→                  key={p.id}
199→                  style={{
200→                    display: 'flex',
201→                    justifyContent: 'space-between',
202→                    alignItems: 'center',
203→                    padding: '10px 12px',
204→                    border: '1px solid var(--color-border)',
205→                    borderRadius: 'var(--radius-md)',
206→                    background: 'var(--color-surface-elevated)',
207→                    fontSize: '13px',
208→                  }}
209→                >
210→                  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
211→                    <span style={{ fontWeight: 500 }}>{p.name}</span>
212→                    <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
213→                      {new Date(p.savedAt).toLocaleDateString()}
214→                    </span>
215→                  </div>
216→                  <div style={{ display: 'flex', gap: '8px' }}>
217→                    <button
218→                      onClick={() => handleLoad(p.id)}
219→                      style={{
220→                        padding: '6px 12px',
221→                        border: '1px solid var(--color-border)',
222→                        borderRadius: 'var(--radius-sm)',
223→                        cursor: 'pointer',
224→                        background: 'var(--color-surface-elevated)',
225→                        fontSize: '12px',
226→                        fontWeight: 500,
227→                      }}
228→                    >
229→                      Load
