237→                        cursor: 'pointer',
238→                        background: 'var(--color-danger-subtle)',
239→                        color: 'var(--color-danger)',
240→                        fontSize: '12px',
241→                      }}
242→                    >
243→                      Delete
244→                    </button>
245→                  </div>
246→                </div>
247→              ))}
248→            </div>
