  1→import { createContext, useContext, useReducer } from 'react';
  2→import { createProject } from '@/domain/models';
  3→import { detachColumnAttachments, syncWallAttachmentPoints } from '@/geometry/wallColumnGeometry';
  4→
  5→const ProjectContext = createContext(null);
  6→const HISTORY_LIMIT = 100;
  7→
  8→function snapshotProject(project) {
  9→  return JSON.stringify(project);
 10→}
 11→
 12→function getFloor(state, floorId) {
 13→  return state.project.floors.find(f => f.id === floorId);
 14→}
 15→
 16→function applyProjectUpdate(state, nextProject, recordHistory = true) {
 17→  const nextSnapshot = snapshotProject(nextProject);
 18→  const history = recordHistory
 19→    ? [...state.history, state.project].slice(-HISTORY_LIMIT)
 20→    : state.history;
 21→
 22→  return {
 23→    ...state,
 24→    history,
 25→    future: recordHistory ? [] : state.future,
 26→    project: nextProject,
 27→    isDirty: nextSnapshot !== state.savedSnapshot,
 28→  };
 29→}
 30→
 31→function updateFloor(state, floorId, updater, recordHistory = true) {
 32→  return applyProjectUpdate(state, {
 33→    ...state.project,
 34→    updatedAt: new Date().toISOString(),
 35→    floors: state.project.floors.map(f =>
 36→      f.id === floorId ? updater(f) : f
 37→    ),
 38→  }, recordHistory);
 39→}
 40→
 41→function mergeWallUpdate(existingWall, wallUpdate, columns = []) {
 42→  const nextWall = { ...existingWall, ...wallUpdate };
 43→
 44→  if ('start' in wallUpdate && !('startAttachment' in wallUpdate)) {
 45→    nextWall.startAttachment = null;
 46→  }
 47→  if ('end' in wallUpdate && !('endAttachment' in wallUpdate)) {
 48→    nextWall.endAttachment = null;
 49→  }
 50→
 51→  return syncWallAttachmentPoints(nextWall, columns);
 52→}
 53→
 54→function projectReducer(state, action) {
 55→  switch (action.type) {
 56→    case 'PROJECT_NEW':
 57→      return {
 58→        project: action.project,
 59→        isDirty: false,
 60→        lastSavedAt: null,
 61→        savedSnapshot: snapshotProject(action.project),
 62→        history: [],
 63→        future: [],
 64→      };
 65→
 66→    case 'PROJECT_LOAD':
 67→      return {
 68→        project: action.project,
 69→        isDirty: false,
 70→        lastSavedAt: action.savedAt || null,
 71→        savedSnapshot: snapshotProject(action.project),
 72→        history: [],
 73→        future: [],
 74→      };
 75→
 76→    case 'PROJECT_SET_NAME':
 77→      return applyProjectUpdate(state, {
 78→        ...state.project,
 79→        name: action.name,
 80→        updatedAt: new Date().toISOString(),
 81→      });
 82→
 83→    case 'SHEET_ADD':
 84→      return applyProjectUpdate(state, {
 85→        ...state.project,
 86→        updatedAt: new Date().toISOString(),
 87→        sheets: [...(state.project.sheets || []), action.sheet],
 88→      });
 89→
 90→    case 'SHEET_UPDATE':
 91→      return applyProjectUpdate(state, {
 92→        ...state.project,
 93→        updatedAt: new Date().toISOString(),
 94→        sheets: (state.project.sheets || []).map((sheet) => (
 95→          sheet.id === action.sheet.id ? { ...sheet, ...action.sheet } : sheet
 96→        )),
 97→      });
 98→
 99→    case 'SHEET_DELETE':
100→      return applyProjectUpdate(state, {
101→        ...state.project,
102→        updatedAt: new Date().toISOString(),
103→        sheets: (state.project.sheets || []).filter((sheet) => sheet.id !== action.sheetId),
104→      });
105→
106→    case 'SHEET_VIEWPORT_ADD':
107→      return applyProjectUpdate(state, {
108→        ...state.project,
109→        updatedAt: new Date().toISOString(),
110→        sheets: (state.project.sheets || []).map((sheet) => (
111→          sheet.id === action.sheetId
112→            ? { ...sheet, viewports: [...(sheet.viewports || []), action.viewport] }
113→            : sheet
114→        )),
115→      });
116→
117→    case 'SHEET_VIEWPORT_UPDATE':
118→      return applyProjectUpdate(state, {
119→        ...state.project,
120→        updatedAt: new Date().toISOString(),
121→        sheets: (state.project.sheets || []).map((sheet) => (
122→          sheet.id === action.sheetId
123→            ? {
124→                ...sheet,
125→                viewports: (sheet.viewports || []).map((viewport) => (
126→                  viewport.id === action.viewport.id ? { ...viewport, ...action.viewport } : viewport
127→                )),
128→              }
129→            : sheet
130→        )),
131→      });
132→
133→    case 'SHEET_VIEWPORT_DELETE':
134→      return applyProjectUpdate(state, {
135→        ...state.project,
136→        updatedAt: new Date().toISOString(),
137→        sheets: (state.project.sheets || []).map((sheet) => (
138→          sheet.id === action.sheetId
139→            ? {
140→                ...sheet,
141→                viewports: (sheet.viewports || []).filter((viewport) => viewport.id !== action.viewportId),
142→              }
143→            : sheet
144→        )),
145→      });
146→
147→    case 'WALL_ADD':
148→      return updateFloor(state, action.floorId, f => ({
149→        ...f,
150→        walls: [...f.walls, syncWallAttachmentPoints(action.wall, f.columns || [])],
151→      }));
152→
153→    case 'WALL_UPDATE':
154→      return updateFloor(state, action.floorId, f => ({
155→        ...f,
156→        walls: f.walls.map(w => (
157→          w.id === action.wall.id
158→            ? mergeWallUpdate(w, action.wall, f.columns || [])
159→            : w
160→        )),
161→      }));
162→
163→    case 'WALL_DELETE': {
164→      const wallId = action.wallId;
165→      return updateFloor(state, action.floorId, f => ({
166→        ...f,
167→        walls: f.walls.filter(w => w.id !== wallId),
168→        doors: f.doors.filter(d => d.wallId !== wallId),
169→        windows: f.windows.filter(w => w.wallId !== wallId),
170→      }));
171→    }
172→
173→    case 'DOOR_ADD':
174→      return updateFloor(state, action.floorId, f => ({
175→        ...f,
176→        doors: [...f.doors, action.door],
177→      }));
178→
179→    case 'DOOR_UPDATE':
180→      return updateFloor(state, action.floorId, f => ({
181→        ...f,
182→        doors: f.doors.map(d => d.id === action.door.id ? { ...d, ...action.door } : d),
183→      }));
184→
185→    case 'DOOR_DELETE':
186→      return updateFloor(state, action.floorId, f => ({
187→        ...f,
188→        doors: f.doors.filter(d => d.id !== action.doorId),
189→      }));
190→
191→    case 'WINDOW_ADD':
192→      return updateFloor(state, action.floorId, f => ({
193→        ...f,
194→        windows: [...f.windows, action.window],
195→      }));
196→
197→    case 'WINDOW_UPDATE':
198→      return updateFloor(state, action.floorId, f => ({
199→        ...f,
200→        windows: f.windows.map(w => w.id === action.window.id ? { ...w, ...action.window } : w),
201→      }));
202→
203→    case 'WINDOW_DELETE':
204→      return updateFloor(state, action.floorId, f => ({
205→        ...f,
206→        windows: f.windows.filter(w => w.id !== action.windowId),
207→      }));
208→
209→    case 'BEAM_ADD':
210→      return updateFloor(state, action.floorId, f => ({
211→        ...f,
212→        beams: [...(f.beams || []), action.beam],
213→      }));
214→
215→    case 'BEAM_UPDATE':
216→      return updateFloor(state, action.floorId, f => ({
217→        ...f,
218→        beams: (f.beams || []).map(beam => (
219→          beam.id === action.beam.id ? { ...beam, ...action.beam } : beam
220→        )),
221→      }));
